// src/contexts/AuthContext.tsx
import React, { createContext, useCallback, useContext, useEffect, useState } from 'react';
import AuthService from '../services/AuthService';
import AuthRepository from '../repositories/AuthRepository';
import UsuarioService from '../services/UsuarioService';
import { Permissao, type Usuario } from '../classes';

type AuthContextValue = {
  user: { id: string; email?: string } | null;
  profile: Usuario | null;
  loading: boolean;
  isAdm: boolean;
  isProfessor: boolean;
  isAluno: boolean;
  refreshProfile: (userIdOverride?: string) => Promise<void>;
};

const AuthContext = createContext<AuthContextValue | null>(null);

export const AuthProvider = ({ children }: { children: React.ReactNode }) => {
  const [user, setUser] = useState<AuthContextValue['user']>(null);
  const [profile, setProfile] = useState<Usuario | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;

    AuthService.getCurrentSession()
      .then(async (session) => {
        if (cancelled) return;
        if (session?.user) {
          setUser(session.user);
          try {
            const prof = await UsuarioService.PesquisaPerfilUsuario(session.user.id);
            if (!cancelled) setProfile(prof);
          } catch {
            /* profile optional on boot */
          }
        }
      })
      .catch(() => {})
      .finally(() => {
        if (!cancelled) setLoading(false);
      });

    const {
      data: { subscription },
    } = AuthService.onAuthStateChange((_event, session) => {
      if (cancelled) return;
      if (session?.user) {
        setUser(session.user);
        setTimeout(() => {
          if (cancelled) return;
          UsuarioService.PesquisaPerfilUsuario(session.user.id)
            .then((prof) => {
              if (!cancelled) setProfile(prof);
            })
            .catch(() => {});
        }, 0);
      } else {
        setUser(null);
        setProfile(null);
      }
    });

    return () => {
      cancelled = true;
      subscription?.unsubscribe();
    };
  }, []);

  const refreshProfile = useCallback(async (userIdOverride?: string) => {
    let id = userIdOverride;
    if (!id) {
      try {
        id = (await AuthRepository.getCurrentUser())?.id;
      } catch {
        id = undefined;
      }
    }
    if (!id) return;
    try {
      const prof = await UsuarioService.PesquisaPerfilUsuario(id);
      setProfile(prof);
    } catch {
      setProfile(null);
    }
  }, []);

  const isAdm = profile?.permissao === Permissao.ADM;
  const isProfessor = profile?.permissao === Permissao.Professor;
  const isAluno = profile?.permissao === Permissao.Aluno;

  return (
    <AuthContext.Provider
      value={{ user, profile, loading, isAdm, isProfessor, isAluno, refreshProfile }}
    >
      {children}
    </AuthContext.Provider>
  );
};

export const useAuth = () => {
  const ctx = useContext(AuthContext);
  if (!ctx) throw new Error('useAuth must be used inside AuthProvider');
  return ctx;
};
